# Conceptual: Role-Based Access Control for agent tools
TOOL_PERMISSIONS = {
    "read_customer_data": ["analyst", "support", "admin"],
    "write_database":     ["admin"],
    "send_email":         ["marketing", "support", "admin"],
    "execute_payment":    ["finance", "admin"],
}

def check_permission(user_role: str, tool_name: str) -> bool:
    allowed = TOOL_PERMISSIONS.get(tool_name, [])
    return user_role in allowed

# In the agent's tool dispatch layer:
def dispatch_tool(tool_name: str, args: dict, user_role: str):
    if not check_permission(user_role, tool_name):
        raise PermissionError(
            f"Role '{user_role}' is not authorised to call '{tool_name}'"
        )
    return tool_registry[tool_name](**args)

from dataclasses import dataclass, field

@dataclass
class TokenBudget:
    max_tokens: int
    used_tokens: int = field(default=0)

    def consume(self, n: int):
        self.used_tokens += n
        if self.used_tokens > self.max_tokens:
            raise BudgetExceededError(
                f"Token budget exceeded: used {self.used_tokens}, limit {self.max_tokens}"
            )

    @property
    def remaining(self) -> int:
        return max(0, self.max_tokens - self.used_tokens)

# Thread-local budget per task — prevents runaway agents
budget = TokenBudget(max_tokens=100_000)

def call_llm(prompt: str) -> str:
    # Estimate tokens before the call (rough heuristic: 1 token ≈ 4 chars)
    estimated = len(prompt) // 4
    budget.consume(estimated)
    return llm_client.complete(prompt)

import time, threading

def run_with_timeout(fn, timeout_seconds: float, *args, **kwargs):
    """Execute fn and raise TimeoutError if it does not complete in time."""
    result = [None]
    error  = [None]

    def target():
        try:
            result[0] = fn(*args, **kwargs)
        except Exception as e:
            error[0] = e

    thread = threading.Thread(target=target, daemon=True)
    thread.start()
    thread.join(timeout=timeout_seconds)

    if thread.is_alive():
        raise TimeoutError(f"Task exceeded SLA of {timeout_seconds}s")
    if error[0]:
        raise error[0]
    return result[0]

from dataclasses import dataclass

@dataclass
class AgentCapability:
    agent_id: str
    skills: list[str]    # e.g. ["sql", "data-analysis", "report-writing"]
    max_concurrent: int
    current_load: int

AGENT_REGISTRY: list[AgentCapability] = [
    AgentCapability("analyst-1",  ["sql", "data-analysis"], 5, 2),
    AgentCapability("writer-1",   ["report-writing", "summarisation"], 10, 7),
    AgentCapability("researcher-1",["web-search", "summarisation"], 8, 1),
]

def route_task(required_skills: list[str]) -> AgentCapability | None:
    candidates = [
        a for a in AGENT_REGISTRY
        if all(s in a.skills for s in required_skills)
        and a.current_load < a.max_concurrent
    ]
    if not candidates:
        return None
    # Pick the least-loaded qualifying agent
    return min(candidates, key=lambda a: a.current_load / a.max_concurrent)

# Tool versioning ensures agents always use a compatible tool contract
TOOL_REGISTRY = {
    "get_customer": {
        "v1": get_customer_v1,  # legacy: returns flat dict
        "v2": get_customer_v2,  # current: returns CustomerProfile model
    }
}

def resolve_tool(name: str, requested_version: str = "v2"):
    versions = TOOL_REGISTRY.get(name)
    if not versions:
        raise KeyError(f"Unknown tool: {name}")
    if requested_version not in versions:
        # Fall back to latest
        requested_version = max(versions.keys())
    return versions[requested_version]

