import re

BLOCKED_PATTERNS = [
    r"DROP TABLE",
    r"DELETE FROM .+ WHERE 1=1",
    r"rm -rf",
    r"sudo ",
]

PII_PATTERNS = [
    r" \d{3}-\d{2}-\d{4} ",    # SSN
    r" \d{16} ",                 # credit card (simplified)
]

def apply_output_guardrails(text: str) -> str:
    """Block dangerous commands and redact PII before returning output."""
    for pattern in BLOCKED_PATTERNS:
        if re.search(pattern, text, re.IGNORECASE):
            raise GuardrailViolation(f"Blocked dangerous pattern: {pattern}")

    for pattern in PII_PATTERNS:
        text = re.sub(pattern, "[REDACTED]", text)

    return text
